#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

#include <omp.h>

void
kmeans_kernel_c(float  *feature,   
			  float  *clusters,
			  int    *membership,
			    int     npoints,
				int     nclusters,
				int     nfeatures,
				int		offset,
				int		size
			  ) 
{
    #pragma omp parallel for schedule(static)
	for (unsigned int point_id = 0; point_id < (unsigned int)npoints; point_id++)
	{
		int index = 0;
		float min_dist=FLT_MAX;
		for (int i=0; i < nclusters; i++) {
			float dist = 0;
			float ans  = 0;
			for (int l=0; l<nfeatures; l++){
				float diff = feature[l * npoints + point_id] - clusters[i*nfeatures+l];
				ans += diff * diff;
			}
			dist = ans;
			if (min_dist > dist) {
				min_dist = dist;
				index    = i;
			}
		}
		membership[point_id] = index;
	}
	return;
}

void
kmeans_swap(float  *feature,   
			float  *feature_swap,
			int     npoints,
			int     nfeatures
){
	#pragma omp parallel for schedule(static)
	for (unsigned int tid = 0; tid < (unsigned int)npoints; tid++) {
		for(int i = 0; i <  nfeatures; i++)
			feature_swap[i * npoints + tid] = feature[tid * nfeatures + i];
	}
}
